#!/bin/bash
set -e
mkdir -p /opt/probe
cat > /tmp/leader-check.sh.b64 <<'B64EOF'

B64EOF
base64 -d /tmp/leader-check.sh.b64 > /opt/probe/leader-check.sh
chmod +x /opt/probe/leader-check.sh
cat > /tmp/collect-cluster.sh.b64 <<'B64EOF'

B64EOF
base64 -d /tmp/collect-cluster.sh.b64 > /opt/probe/collect-cluster.sh
chmod +x /opt/probe/collect-cluster.sh
echo UPLOADED; ls -la /opt/probe/*.sh

